  const hi = Math.floor(v / 65536) % 256;
  const lo = v % 256;
  let a = hi, b = lo, result = 0, bv = 1;
  while (a > 0 || b > 0) {
    if ((a % 2) !== (b % 2)) result += bv;
    a = Math.floor(a / 2);
    b = Math.floor(b / 2);
    bv *= 2;
  }
  return result % 256;
}

function mxor(a, b) {
  let r = 0, bv = 1;
  while (a > 0 || b > 0) {
    if ((a % 2) !== (b % 2)) r += bv;
    a = Math.floor(a / 2);
    b = Math.floor(b / 2);
    bv *= 2;
  }
  return r;
}

