import { randomBytes } from "crypto";

function deriveKeyByte(seed, index) {
  let v = seed;
  v = (v * 1103515245 + 12345 + index * 7919) % 2147483647;
  const hi = Math.floor(v / 65536) % 256;
  const lo = v % 256;
  let a = hi, b = lo, result = 0, bv = 1;
  while (a > 0 || b > 0) {
    if ((a % 2) !== (b % 2)) result += bv;
    a = Math.floor(a / 2);
    b = Math.floor(b / 2);
    bv *= 2;
  }
  return result % 256;
}

function mxor(a, b) {
  let r = 0, bv = 1;
  while (a > 0 || b > 0) {
    if ((a % 2) !== (b % 2)) r += bv;
    a = Math.floor(a / 2);
    b = Math.floor(b / 2);
    bv *= 2;
  }
  return r;
}

const seed = 12345;
const saltSeed = 67890;
const keyLength = 24;

const rawKey = [];
for (let i = 0; i < keyLength; i++) rawKey.push(deriveKeyByte(seed, i));

const saltKey = [];
for (let i = 0; i < keyLength; i++) saltKey.push(deriveKeyByte(saltSeed, i));

const rotation = Math.floor(seed / 256) % 256;
const posKey = Math.floor(saltSeed / 65536) % 256;

console.log("Rotation:", rotation, "PosKey:", posKey);

const source = "print('hello')";
const sourceBytes = Array.from(Buffer.from(source, "utf8"));
console.log("Source:", sourceBytes);

// Encrypt
const encrypted = sourceBytes.map((byte, i) => {
  let b = mxor(byte, rawKey[i % rawKey.length]) % 256;
  b = mxor(b, saltKey[i % saltKey.length]) % 256;
  b = (b + rotation) % 256;
  b = mxor(b, (posKey + i) % 256) % 256;
  return b;
});
console.log("Encrypted:", encrypted);

// Simulate Lua decryption
function dk(s, i) {
  let v = s;
  v = (v * 1103515245 + 12345 + i * 7919) % 2147483647;
  const hi = Math.floor(v / 65536) % 256;
  const lo = v % 256;
  return mxor(hi, lo) % 256;
}

const k = [];
for (let i = 1; i <= encrypted.length; i++) {
  k[i-1] = mxor(dk(seed, i-1), dk(saltSeed, i-1));
}

const s2 = [];
for (let i = 1; i <= encrypted.length; i++) {
  s2[i-1] = dk(saltSeed, i-1);
}

const r = Math.floor(seed / 256) % 256;
const p = Math.floor(saltSeed / 65536) % 256;

// Decrypt: reverse order
const decrypted = encrypted.map((encByte, i) => {
  let v = encByte;
  v = mxor(v, (p + i) % 256) % 256;  // reverse pos XOR
  v = ((v - r) % 256 + 256) % 256;   // reverse rotation (handle negative)
  v = mxor(v, s2[i]) % 256;          // reverse salt XOR
  v = mxor(v, k[i]) % 256;           // reverse key XOR
  return v;
});

